flicker     = 0    # anti-flicker mode (0=OFF, 1=50Hz, 2=60Hz, 3=AUTO)
tinterval   = 5.0   # time between timelapse shots in seconds
tshots      = 10   # number of timelapse shots
saturation  = 10   # picture colour saturation
