def draw_jsk_controls(screen_width, screen_height, image_array=None):
    """
    Dessine le panneau de contrôle JSK LIVE sur le côté droit, avec onglets.

    Args:
        screen_width: Largeur de l'écran
        screen_height: Hauteur de l'écran
        image_array: Image pour histogramme (optionnel)

    Returns:
        Dict avec les rects des contrôles pour détection clics
    """
    global windowSurfaceObj, _font_cache
    global jsk_stack_count, jsk_hdr_bits_clip, jsk_hdr_method, jsk_use_ema
    global jsk_denoise_type, jsk_denoise_strength
    global jsk_hdr_methods, jsk_denoise_types, jsk_hdr_weights
    global stretch_preset, ghs_D, ghs_b, ghs_SP, ghs_LP, ghs_HP
    global stretch_factor
    global log_factor, mtf_shadows, mtf_midtone, mtf_highlights
    global jsk_color_enabled, jsk_r_gain, jsk_g_gain, jsk_b_gain, jsk_contrast
    global jsk_settings_tab

    control_rects = {}

    # Panneau latéral droit
    panel_width = 280
    panel_margin = 20
    panel_x = screen_width - panel_width - panel_margin
    start_y = 90

    # Fond semi-transparent du panneau
    panel_height = screen_height - 120
    s = pygame.Surface((panel_width + 20, panel_height), pygame.SRCALPHA)
    s.fill((20, 20, 30, 180))
    windowSurfaceObj.blit(s, (panel_x - 10, start_y - 20))

    # Fontes
    cache_key = 24
    if cache_key not in _font_cache:
        _font_cache[cache_key] = pygame.font.Font(None, cache_key)
    titleFont = _font_cache[cache_key]

    cache_key_section = 18
    if cache_key_section not in _font_cache:
        _font_cache[cache_key_section] = pygame.font.Font(None, cache_key_section)
    sectionFont = _font_cache[cache_key_section]

    # Titre
    title = titleFont.render("JSK LIVE Settings", True, (200, 180, 100))
    windowSurfaceObj.blit(title, (panel_x, start_y - 15))
    start_y += 25

    slider_width = 250
    slider_height = 30
    margin = 4

    # ===== Onglets =====
    tab_labels = ["Image", "Couleur"]
    tab_count = len(tab_labels)
    tab_gap = 4
    tab_w = (slider_width - tab_gap * (tab_count - 1)) // tab_count
    tab_h = 26

    for i, lbl in enumerate(tab_labels):
        tx = panel_x + i * (tab_w + tab_gap)
        ty = start_y
        tab_rect = pygame.Rect(tx, ty, tab_w, tab_h)
        control_rects[f'jsk_tab_{i}'] = tab_rect

        if jsk_settings_tab == i:
            tab_bg = (55, 70, 95)
            tab_border = (140, 170, 210)
            text_col = (230, 235, 255)
        else:
            tab_bg = (28, 28, 38)
            tab_border = (65, 65, 78)
            text_col = (120, 125, 145)

        pygame.draw.rect(windowSurfaceObj, tab_bg, tab_rect, border_radius=4)
        pygame.draw.rect(windowSurfaceObj, tab_border, tab_rect, 1, border_radius=4)
        tab_surf = sectionFont.render(lbl, True, text_col)
        windowSurfaceObj.blit(tab_surf, (
            tx + (tab_w - tab_surf.get_width()) // 2,
            ty + (tab_h - tab_surf.get_height()) // 2
        ))

    start_y += tab_h + 10

    # ===== Contenu selon l'onglet actif =====
    if jsk_settings_tab == 0:
        # ------ Onglet 0 : Image (HDR / Denoise / Stretch) ------

        # Section HDR
        section = sectionFont.render("HDR Processing:", True, (150, 180, 200))
        windowSurfaceObj.blit(section, (panel_x, start_y))
        start_y += 16

        control_rects['jsk_stack'] = draw_jsk_slider(
            panel_x, start_y, slider_width, slider_height,
            f"Stack: {jsk_stack_count}", jsk_stack_count, 1, 10, (100, 180, 140)
        )
        start_y += slider_height + margin

        ema_label = f"Mode: {'EMA  (α={:.2f})'.format(2.0/(jsk_stack_count+1)) if jsk_use_ema else 'Window'}"
        control_rects['jsk_ema_toggle'] = draw_jsk_slider(
            panel_x, start_y, slider_width, slider_height,
            ema_label, jsk_use_ema, 0, 1, (100, 160, 200)
        )
        start_y += slider_height + margin

        control_rects['jsk_hdr_method'] = draw_jsk_slider(
            panel_x, start_y, slider_width, slider_height,
            f"HDR: {jsk_hdr_methods[jsk_hdr_method]}", jsk_hdr_method, 0, 3, (140, 100, 180)
        )
        start_y += slider_height + margin

        if jsk_hdr_method > 0:
            clip_label = "HDR Clip: OFF" if jsk_hdr_bits_clip == 0 else f"HDR Clip: {jsk_hdr_bits_clip} bits"
            control_rects['jsk_hdr_clip'] = draw_jsk_slider(
                panel_x, start_y, slider_width, slider_height,
                clip_label, jsk_hdr_bits_clip, 0, 3, (180, 140, 100)
            )
            start_y += slider_height + margin

        start_y += 6

        # Section Denoise
        section = sectionFont.render("Denoise:", True, (150, 180, 200))
        windowSurfaceObj.blit(section, (panel_x, start_y))
        start_y += 16

        control_rects['jsk_denoise_type'] = draw_jsk_slider(
            panel_x, start_y, slider_width, slider_height,
            f"Type: {jsk_denoise_types[jsk_denoise_type]}", jsk_denoise_type, 0, 4, (100, 140, 180)
        )
        start_y += slider_height + margin

        control_rects['jsk_denoise_strength'] = draw_jsk_slider(
            panel_x, start_y, slider_width, slider_height,
            f"Strength: {jsk_denoise_strength}", jsk_denoise_strength, 1, 10, (180, 160, 100)
        )
        start_y += slider_height + margin + 6

        # Section Stretch
        section = sectionFont.render("Stretch:", True, (150, 180, 200))
        windowSurfaceObj.blit(section, (panel_x, start_y))
        start_y += 16

        stretch_names = ['OFF', 'GHS', 'Arcsinh', 'Log', 'MTF']
        control_rects['jsk_stretch_preset'] = draw_jsk_slider(
            panel_x, start_y, slider_width, slider_height,
            f"Preset: {stretch_names[min(stretch_preset, 4)]}", stretch_preset, 0, 4, (160, 140, 180)
        )
        start_y += slider_height + margin

        if stretch_preset == 1:
            control_rects['jsk_ghs_D'] = draw_jsk_slider(
                panel_x, start_y, slider_width, slider_height,
                f"D (Stretch): {ghs_D/10:.1f}", ghs_D, -10, 100, (100, 180, 140)
            )
            start_y += slider_height + margin

            control_rects['jsk_ghs_b'] = draw_jsk_slider(
                panel_x, start_y, slider_width, slider_height,
                f"b (Local Int): {ghs_b/10:.1f}", ghs_b, -300, 100, (100, 160, 180)
            )
            start_y += slider_height + margin

            control_rects['jsk_ghs_SP'] = draw_jsk_slider(
                panel_x, start_y, slider_width, slider_height,
                f"SP (Symmetry): {ghs_SP/100:.2f}", ghs_SP, 0, 100, (180, 140, 100)
            )
            start_y += slider_height + margin

            control_rects['jsk_ghs_LP'] = draw_jsk_slider(
                panel_x, start_y, slider_width, slider_height,
                f"LP (Shadows): {ghs_LP/100:.2f}", ghs_LP, 0, 100, (140, 100, 180)
            )
            start_y += slider_height + margin

            control_rects['jsk_ghs_HP'] = draw_jsk_slider(
                panel_x, start_y, slider_width, slider_height,
                f"HP (Highlights): {ghs_HP/100:.2f}", ghs_HP, 0, 100, (180, 100, 140)
            )

        elif stretch_preset == 2:
            control_rects['jsk_stretch_factor'] = draw_jsk_slider(
                panel_x, start_y, slider_width, slider_height,
                f"Factor: {stretch_factor/10:.1f}", stretch_factor, 0, 1000, (200, 160, 100)
            )

        elif stretch_preset == 3:
            control_rects['jsk_log_factor'] = draw_jsk_slider(
                panel_x, start_y, slider_width, slider_height,
                f"Log Factor: {log_factor}", log_factor, 0, 1000, (120, 170, 50)
            )

        elif stretch_preset == 4:
            control_rects['jsk_mtf_shadows'] = draw_jsk_slider(
                panel_x, start_y, slider_width, slider_height,
                f"Shadows: {mtf_shadows/100:.2f}", mtf_shadows, 0, 50, (80, 120, 160)
            )
            start_y += slider_height + margin

            control_rects['jsk_mtf_midtone'] = draw_jsk_slider(
                panel_x, start_y, slider_width, slider_height,
                f"Midtone: {mtf_midtone/100:.2f}", mtf_midtone, 1, 99, (50, 160, 200)
            )
            start_y += slider_height + margin

            control_rects['jsk_mtf_highlights'] = draw_jsk_slider(
                panel_x, start_y, slider_width, slider_height,
                f"Highlights: {mtf_highlights/100:.2f}", mtf_highlights, 50, 100, (100, 200, 220)
            )

    else:
        # ------ Onglet 1 : Couleur & Contraste ------
        section = sectionFont.render("Color & Contrast:", True, (150, 180, 200))
        windowSurfaceObj.blit(section, (panel_x, start_y))
        start_y += 16

        # Toggle ON/OFF
        cc_label = "Couleur: ON" if jsk_color_enabled else "Couleur: OFF"
        cc_color = (80, 200, 100) if jsk_color_enabled else (140, 80, 80)
        control_rects['jsk_color_enabled'] = draw_jsk_slider(
            panel_x, start_y, slider_width, slider_height,
            cc_label, jsk_color_enabled, 0, 1, cc_color
        )
        start_y += slider_height + margin + 6

        if jsk_color_enabled:
            control_rects['jsk_r'] = draw_jsk_slider(
                panel_x, start_y, slider_width, slider_height,
                f"R: {jsk_r_gain/100:.2f}x", jsk_r_gain, 50, 200, (200, 80, 80)
            )
            start_y += slider_height + margin

            control_rects['jsk_g'] = draw_jsk_slider(
                panel_x, start_y, slider_width, slider_height,
                f"G: {jsk_g_gain/100:.2f}x", jsk_g_gain, 50, 200, (80, 200, 80)
            )
            start_y += slider_height + margin

            control_rects['jsk_b'] = draw_jsk_slider(
                panel_x, start_y, slider_width, slider_height,
                f"B: {jsk_b_gain/100:.2f}x", jsk_b_gain, 50, 200, (80, 120, 220)
            )
            start_y += slider_height + margin

            control_rects['jsk_contrast'] = draw_jsk_slider(
                panel_x, start_y, slider_width, slider_height,
                f"Contraste: {jsk_contrast/100:.2f}x", jsk_contrast, 50, 200, (200, 200, 80)
            )

    # ===== Panneau gauche : HDR Weights (uniquement en mode Mean) =====
    if jsk_hdr_method == 2:
        left_panel_width = 220
        left_panel_x = panel_margin
        left_start_y = 90
        n_weights = jsk_hdr_bits_clip + 1  # 2, 3 ou 4 sliders

        # Fond semi-transparent
        left_panel_height = 50 + n_weights * (slider_height + margin)
        s_left = pygame.Surface((left_panel_width + 20, left_panel_height), pygame.SRCALPHA)
        s_left.fill((20, 20, 30, 180))
        windowSurfaceObj.blit(s_left, (left_panel_x - 10, left_start_y - 20))

        # Titre
        title_left = titleFont.render("HDR Weights", True, (200, 180, 100))
        windowSurfaceObj.blit(title_left, (left_panel_x, left_start_y - 15))
        left_start_y += 25

        # Labels pour chaque niveau de bit
        bit_labels = ["12-bit", "11-bit", "10-bit", "9-bit", "8-bit", "7-bit"]
        weight_colors = [(140, 200, 140), (200, 180, 100), (200, 140, 100), (200, 100, 100), (180, 80, 120), (160, 60, 140)]

        left_slider_width = 200

        for i in range(n_weights):
            w_val = jsk_hdr_weights[i]
            control_rects[f'jsk_hdr_w{i}'] = draw_jsk_slider(
                left_panel_x, left_start_y, left_slider_width, slider_height,
                f"{bit_labels[i]}: {w_val}%", w_val, 0, 100, weight_colors[i]
            )
            left_start_y += slider_height + margin

    return control_rects


def draw_jsk_gain_exposure(screen_width, screen_height):
    """
    Dessine les sliders Gain et Exposition en bas de l'ecran JSK LIVE,
    a droite du bouton EXIT. Toujours visibles.
    Gain: 1-400 lineaire. Expo: 1ms-1000ms log.
    """
    global windowSurfaceObj, _font_cache
    global jsk_gain, jsk_exposure_us

    slider_w = 200
    slider_h = 30
    gap = 5
    # Positionner a droite du bouton EXIT (EXIT = 15+50=65 de large)
    sx = 80
    margin_y = 15

    # --- Slider Exposition (en bas) ---
    sy_expo = screen_height - slider_h - margin_y

    bg_rect_expo = pygame.Rect(sx, sy_expo, slider_w, slider_h)
    pygame.draw.rect(windowSurfaceObj, (40, 40, 50), bg_rect_expo, border_radius=5)
    pygame.draw.rect(windowSurfaceObj, (80, 80, 90), bg_rect_expo, 1, border_radius=5)

    min_exp_ms = 1
    max_exp_ms = 2000
    min_exp_us = min_exp_ms * 1000
    max_exp_us = max_exp_ms * 1000

    exp_clamped = max(min_exp_us, min(jsk_exposure_us, max_exp_us))
    log_min = math.log10(min_exp_us)
    log_max = math.log10(max_exp_us)
    log_val = math.log10(exp_clamped)
    fill_ratio = (log_val - log_min) / (log_max - log_min)
    fill_w = int(fill_ratio * (slider_w - 10))
    fill_rect = pygame.Rect(sx + 5, sy_expo + 5, max(1, fill_w), slider_h - 10)
    pygame.draw.rect(windowSurfaceObj, (60, 100, 120), fill_rect, border_radius=3)

    cache_key = 20
    if cache_key not in _font_cache:
        _font_cache[cache_key] = pygame.font.Font(None, cache_key)
    fontObj = _font_cache[cache_key]

    expo_ms = jsk_exposure_us / 1000.0
    if expo_ms < 10:
        expo_text = f"Expo: {expo_ms:.1f}ms"
    else:
        expo_text = f"Expo: {expo_ms:.0f}ms"
    label_surf = fontObj.render(expo_text, True, (200, 200, 200))
    label_rect = label_surf.get_rect(center=bg_rect_expo.center)
    windowSurfaceObj.blit(label_surf, label_rect)

    # --- Slider Gain (au-dessus de l'expo) ---
    sy_gain = sy_expo - slider_h - gap

    bg_rect_gain = pygame.Rect(sx, sy_gain, slider_w, slider_h)
    pygame.draw.rect(windowSurfaceObj, (40, 40, 50), bg_rect_gain, border_radius=5)
    pygame.draw.rect(windowSurfaceObj, (80, 80, 90), bg_rect_gain, 1, border_radius=5)

    fill_ratio = min(1.0, (jsk_gain - 1) / 399.0)
    fill_w = int(fill_ratio * (slider_w - 10))
    if fill_w > 0:
        fill_rect = pygame.Rect(sx + 5, sy_gain + 5, fill_w, slider_h - 10)
        pygame.draw.rect(windowSurfaceObj, (120, 100, 60), fill_rect, border_radius=3)

    gain_text = f"Gain: {jsk_gain}"
    label_surf = fontObj.render(gain_text, True, (200, 200, 200))
    label_rect = label_surf.get_rect(center=bg_rect_gain.center)
    windowSurfaceObj.blit(label_surf, label_rect)


def _jsk_ge_slider_positions(screen_height):
    """Retourne les positions (sx, sy_gain, sy_expo, slider_w, slider_h) des sliders gain/expo."""
    slider_w = 200
    slider_h = 30
    gap = 5
    sx = 80
    margin_y = 15
    sy_expo = screen_height - slider_h - margin_y
    sy_gain = sy_expo - slider_h - gap
    return sx, sy_gain, sy_expo, slider_w, slider_h


def is_click_on_jsk_gain_slider(mousex, mousey, screen_width, screen_height):
    """Verifie si clic sur slider gain JSK. Retourne la nouvelle valeur (1-400) ou None."""
    sx, sy_gain, _, slider_w, slider_h = _jsk_ge_slider_positions(screen_height)

    if sx <= mousex <= sx + slider_w and sy_gain <= mousey <= sy_gain + slider_h:
        rel_x = mousex - sx
        ratio = max(0.0, min(1.0, rel_x / slider_w))
        value = int(1 + ratio * 399)
        return max(1, min(400, value))
    return None


def is_click_on_jsk_exposure_slider(mousex, mousey, screen_width, screen_height):
    """Verifie si clic sur slider exposure JSK. Retourne la valeur en us (1000-2000000) ou None."""
    sx, _, sy_expo, slider_w, slider_h = _jsk_ge_slider_positions(screen_height)

    if sx <= mousex <= sx + slider_w and sy_expo <= mousey <= sy_expo + slider_h:
        min_exp_us = 1000    # 1ms
        max_exp_us = 2000000 # 2000ms

        rel_x = mousex - sx
        ratio = max(0.0, min(1.0, rel_x / slider_w))
        # Echelle logarithmique
        log_min = math.log10(min_exp_us)
        log_max = math.log10(max_exp_us)
        log_val = log_min + ratio * (log_max - log_min)
        value_us = int(10 ** log_val)
        return max(min_exp_us, min(value_us, max_exp_us))
    return None


